def get_registered_settings(self, category_slug=None, read_only=None, slugs_to_ignore=set()):
    if category_slug == 'user-defaults':
        category_slug = 'user'
    if category_slug == 'changed':
        category_slug = 'all'

    return [
        setting for setting, kwargs in self._registry.items()
        if category_slug in {None, 'all', kwargs.get('category_slug', None)}
        and kwargs.get('category_slug', None) not in slugs_to_ignore
        and (not (read_only in {True, False} and kwargs.get('read_only', False) != read_only and setting != 'INSTALL_UUID'))
    ]

