                segment[tgt],
                segment["speaker_id"],
                tgt,
                f"{wav_path.stem}_{i}",
            )
            for wav_filename, _seg_group in groupby(segments, lambda x: x["wav"])
            for i, segment in enumerate(sorted(_seg_group, key=lambda x: float(x["offset"])))
        ]

