def render_headers(self):
        """
        Renders the headers for this request field.
        """
        sort_keys = ["Content-Disposition", "Content-Type", "Content-Location"]

        # First list comprehension for sorted keys
        lines = [
            u"%s: %s" % (sort_key, self.headers[sort_key]) 
            for sort_key in sort_keys 
            if self.headers.get(sort_key, False)
        ]

        # Second list comprehension for remaining headers not in sort_keys
        lines.extend(
            u"%s: %s" % (header_name, header_value) 
            for header_name, header_value in self.headers.items() 
            if header_name not in sort_keys and header_value
        )

        lines.append(u"\r\n")
        return u"\r\n".join(lines)

